#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <sys/types.h>
#include <sys/stat.h>
#include <fcntl.h>

// Structure to hold file handle information
typedef struct {
    int fd; // File descriptor
    char* filename; // Filename
} FileHandle;

// Array to store all the file handles
FileHandle* fileHandles = NULL;

// Function to add a new file handle to the pool
void addFileHandle(int fd, const char* filename) {
    // Allocate memory for the new file handle
    FileHandle* newHandle = (FileHandle*)malloc(sizeof(FileHandle));
    if (!newHandle) {
        perror("Failed to allocate memory for new file handle");
        exit(1);
    }

    // Initialize the file handle fields
    newHandle->fd = fd;
    newHandle->filename = strdup(filename);

    // Add the new file handle to the pool
    if (fileHandles == NULL) {
        fileHandles = newHandle;
    } else {
        FileHandle* current = fileHandles;
        while (current->next != NULL) {
            current = current->next;
        }
        current->next = newHandle;
    }
}

// Function to remove a file handle from the pool
void removeFileHandle(int fd) {
    // Find the file handle with the given file descriptor
    FileHandle* current = fileHandles;
    while (current != NULL && current->fd != fd) {
        current = current->next;
    }

    // If the file handle was found, remove it from the pool
    if (current != NULL) {
        // Free the filename string
        free(current->filename);

        // Remove the file handle from the pool
        if (current == fileHandles) {
            fileHandles = current->next;
        } else {
            FileHandle* previous = fileHandles;
            while (previous->next != current) {
                previous = previous->next;
            }
            previous->next = current->next;
        }

        // Free the memory allocated for the file handle
        free(current);
    }
}

// Function to clean up all file handles in the pool
void cleanupFileHandles() {
    // Iterate through the file handles and close each one
    FileHandle* current = fileHandles;
    while (current != NULL) {
        // Close the file descriptor
        if (close(current->fd) == -1) {
            perror("Failed to close file descriptor");
        }

        // Free the filename string
        free(current->filename);

        // Remove the file handle from the pool
        FileHandle* next = current->next;
        free(current);
        current = next;
    }
}

int main() {
    // Add some file handles to the pool
    addFileHandle(open("file1.txt", O_RDONLY), "file1.txt");
    addFileHandle(open("file2.txt", O_RDONLY), "file2.txt");

    // Remove a file handle from the pool
    removeFileHandle(open("file1.txt", O_RDONLY));

    // Clean up all file handles in the pool
    cleanupFileHandles();

    return 0;
}